package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="progress_logs") public class ProgressLog { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="user_id",nullable=false) private User user; @Column(name="log_date") private LocalDate logDate; @Column(name="weight_kg",precision=5,scale=2) private BigDecimal weightKg; @Column(name="body_fat_percentage",precision=5,scale=2) private BigDecimal bodyFatPercentage; @Column(name="muscle_mass",precision=5,scale=2) private BigDecimal muscleMass; @Column(precision=5,scale=2) private BigDecimal bmi; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; }
